#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        arrivals = [int(next(it)) for _ in range(N)]
        departures = [int(next(it)) for _ in range(N)]
        arrivals.sort()
        departures.sort()
        i = j = cur = best = 0
        while i < N and j < N:
            if arrivals[i] < departures[j]:
                cur += 1
                if cur > best:
                    best = cur
                i += 1
            else:
                cur -= 1
                j += 1
        out_lines.append(str(best))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

